// Esposto per la pagina admin di verifica i18n
export const __DICT__ = DICT;

type I18nCtx = {
  lang: Lang;
  setLang: (l: Lang) => void;
  t: (key: string, vars?: Record<string, string | number>) => string;
  country: string | null;
  currency: Currency;
  setCurrency: (c: Currency) => void;
  /** Format an EUR amount using current currency + locale, with live FX. */
  price: (eurAmount: number) => string;
  /** Convert an EUR amount to the active display currency (raw number, 2 decimals). */
  convert: (eurAmount: number) => number;
};

const Ctx = createContext<I18nCtx>({
  lang: "it",
  setLang: () => {},
  t: (k) => k,
  country: null,
  currency: "EUR",
  setCurrency: () => {},
  price: (n) => `€ ${n.toFixed(2)}`,
  convert: (n) => Math.round(n * 100) / 100,
});

const STORAGE_KEY = "lp_lang";
const STORAGE_LANG_SOURCE = "lp_lang_source"; // "user" | "auto"
const STORAGE_COUNTRY = "lp_country";
const STORAGE_CURRENCY = "lp_currency";
const STORAGE_CURRENCY_SOURCE = "lp_currency_source"; // "user" | "auto"
const STORAGE_GEO_TS = "lp_geo_ts";

// Mappa paese → valuta locale. 27 paesi UE + EEA + UK/CH/IS/US.
// Mappa paese → valuta locale (UE + EEA + mercati extra-UE).
const COUNTRY_TO_CURRENCY: Record<string, Currency> = {
  // Eurozona (20 UE)
  AT: "EUR", BE: "EUR", CY: "EUR", DE: "EUR", EE: "EUR", ES: "EUR", FI: "EUR",
  FR: "EUR", GR: "EUR", HR: "EUR", IE: "EUR", IT: "EUR", LT: "EUR", LU: "EUR",
  LV: "EUR", MT: "EUR", NL: "EUR", PT: "EUR", SI: "EUR", SK: "EUR",
  // UE non-Eurozona — valute proprie
  BG: "BGN", CZ: "CZK", DK: "DKK", HU: "HUF", PL: "PLN", RO: "RON", SE: "SEK",
  // EEA / vicini
  GB: "GBP", CH: "CHF", NO: "NOK", IS: "ISK", LI: "CHF", AD: "EUR", MC: "EUR", SM: "EUR", VA: "EUR",
  // Americas / Pacific
  US: "USD", CA: "CAD", AU: "AUD", NZ: "NZD",
  // Asia
  JP: "JPY", KR: "KRW", TW: "TWD", HK: "HKD", SG: "SGD",
  // Medio Oriente
  AE: "AED", QA: "QAR", KW: "KWD", SA: "SAR", IL: "ILS",
};

const COUNTRY_TO_LANG: Record<string, Lang> = {
  IT: "it", SM: "it", VA: "it",
  GB: "en", IE: "en", US: "en", CA: "en", AU: "en", NZ: "en", SG: "en",
  DE: "de", AT: "de", LI: "de", CH: "de",
  FR: "fr", BE: "fr", LU: "fr", MC: "fr",
  ES: "es", AD: "es",
  PT: "pt",
  NL: "nl",
  // Nuove lingue UE
  BG: "bg", CZ: "cs", DK: "da", GR: "el", EE: "et", FI: "fi",
  HR: "hr", HU: "hu", LT: "lt", LV: "lv", MT: "mt", PL: "pl",
  RO: "ro", SK: "sk", SI: "sl", SE: "sv",
  CY: "el",
  // Extra-UE
  NO: "no", IS: "is",
  JP: "ja", KR: "ko",
  TW: "zh", HK: "zh",
  AE: "ar", QA: "ar", KW: "ar", SA: "ar",
  IL: "he",
};

function langFromCountry(country: string | null): Lang | null {
  if (!country) return null;
  return COUNTRY_TO_LANG[country] || "en";
}

function currencyFromCountry(country: string | null, detectedCurrency?: string | null): Currency | null {
  if (!country) return null;
  return (detectedCurrency || COUNTRY_TO_CURRENCY[country] || "EUR") as Currency;
}

export function I18nProvider({ children }: { children: ReactNode }) {
  const [lang, setLangState] = useState<Lang>("en");
  const [country, setCountry] = useState<string | null>(null);
  const [currency, setCurrencyState] = useState<Currency>("EUR");
  const [rates, setRates] = useState<Record<string, number>>({ EUR: 1 });
  const [uiTranslations, setUiTranslations] = useState<Record<string, string>>({});

  // Carica i tassi di cambio (cachati 1h)
  useEffect(() => {
    let cancelled = false;
    getRates().then((r) => { if (!cancelled) setRates(r); });
    return () => { cancelled = true; };
  }, []);

  useEffect(() => {
    if (lang === "it") {
      setUiTranslations({});
      return;
    }
    let cancelled = false;
    supabase
      .from("translations")
      .select("field, value")
      .eq("entity_type", "ui")
      .eq("entity_id", "i18n")
      .eq("lang", lang)
      .then(({ data }) => {
        if (cancelled) return;
        const next: Record<string, string> = {};
        for (const row of data || []) {
          if (row.field && row.value) next[row.field] = row.value;
        }
        setUiTranslations(next);
      });
    return () => { cancelled = true; };
  }, [lang]);

  // Imposta direzione del documento per lingue RTL (ar, he)
  useEffect(() => {
    if (typeof document === "undefined") return;
    const isRtl = lang === "ar" || lang === "he";
    document.documentElement.dir = isRtl ? "rtl" : "ltr";
  }, [lang]);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const firstPathSegment = window.location.pathname.split("/").filter(Boolean)[0] as Lang | undefined;
    const pathLang = firstPathSegment && SUPPORTED_LANGS.find((s) => s.code === firstPathSegment)
      ? firstPathSegment
      : null;

    const savedLang = localStorage.getItem(STORAGE_KEY) as Lang | null;
    const cachedCountry = localStorage.getItem(STORAGE_COUNTRY);
    const savedCurrency = localStorage.getItem(STORAGE_CURRENCY) as Currency | null;

    // 1. Hydrate immediato. Se abbiamo già il paese IP in cache,
    // deve comandare lui: selettore lingua e valuta restano allineati all'IP.
    const cachedAutoLang = langFromCountry(cachedCountry);
    const cachedAutoCurrency = currencyFromCountry(cachedCountry);

    if (cachedCountry) setCountry(cachedCountry);
    if (pathLang) {
      setLangState(pathLang);
      localStorage.setItem(STORAGE_KEY, pathLang);
      localStorage.setItem(STORAGE_LANG_SOURCE, "url");
      document.documentElement.lang = pathLang;
    } else if (cachedAutoLang) {
      setLangState(cachedAutoLang);
      localStorage.setItem(STORAGE_KEY, cachedAutoLang);
      localStorage.setItem(STORAGE_LANG_SOURCE, "auto");
      document.documentElement.lang = cachedAutoLang;
    } else if (savedLang && SUPPORTED_LANGS.find((s) => s.code === savedLang)) {
      setLangState(savedLang);
      document.documentElement.lang = savedLang;
    } else {
      const browserLang = (navigator.language || "en").slice(0, 2).toLowerCase() as Lang;
      if (SUPPORTED_LANGS.find((s) => s.code === browserLang)) {
        setLangState(browserLang);
        document.documentElement.lang = browserLang;
      } else {
        setLangState("en");
        document.documentElement.lang = "en";
      }
    }
    if (cachedAutoCurrency) {
      setCurrencyState(cachedAutoCurrency);
      localStorage.setItem(STORAGE_CURRENCY, cachedAutoCurrency);
      localStorage.setItem(STORAGE_CURRENCY_SOURCE, "auto");
    } else if (savedCurrency) setCurrencyState(savedCurrency);

    // Verifica SEMPRE l'IP in background: la cache serve solo per l'hydrate immediato.
    // Così se l'utente cambia paese/rete, selettore lingua e valuta si aggiornano subito.

    const ctrl = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), 5000);

    // Differiamo il geo-detect a dopo il first paint per non bloccare LCP/TBT.
    // ipapi.co + edge fallback erano il principale collo di bottiglia critico.
    const runGeoDetect = async () => {
      let detectedCountry: string | null = null;
      let detectedLang: Lang | null = null;
      let detectedCurrency: string | null = null;
      try {
        const r = await fetch("https://ipapi.co/json/", { signal: ctrl.signal });
        if (r.ok) {
          const j = await r.json();
          if (j?.country_code && typeof j.country_code === "string") {
            detectedCountry = j.country_code.toUpperCase();
          }
          if (j?.currency && typeof j.currency === "string") {
            detectedCurrency = j.currency.toUpperCase();
          }
        }
      } catch {
        /* proviamo fallback edge */
      }

      if (!detectedCountry) {
        try {
          const { data, error } = await supabase.functions.invoke("geo-detect");
          if (!error) {
            detectedCountry = data?.country || null;
            if (data?.lang && SUPPORTED_LANGS.find((s) => s.code === data.lang)) {
              detectedLang = data.lang as Lang;
            }
            if (data?.currency) detectedCurrency = data.currency;
          }
        } catch { /* ignora */ }
      }

      try {
        if (detectedCountry && !detectedLang) {
          detectedLang = langFromCountry(detectedCountry);
        }

        localStorage.setItem(STORAGE_GEO_TS, String(Date.now()));

        if (detectedCountry) {
          setCountry(detectedCountry);
          localStorage.setItem(STORAGE_COUNTRY, detectedCountry);
        }

        if (detectedLang && !pathLang) {
          const finalLang = detectedLang;
          setLangState(finalLang);
          localStorage.setItem(STORAGE_KEY, finalLang);
          localStorage.setItem(STORAGE_LANG_SOURCE, "auto");
          document.documentElement.lang = finalLang;
        }

        if (detectedCountry) {
          const cur = currencyFromCountry(detectedCountry, detectedCurrency) || "EUR";
          setCurrencyState(cur);
          localStorage.setItem(STORAGE_CURRENCY, cur);
          localStorage.setItem(STORAGE_CURRENCY_SOURCE, "auto");
        }
      } catch {
        /* fallback già applicato */
      } finally {
        clearTimeout(timer);
      }
    };

    // requestIdleCallback dove disponibile, altrimenti setTimeout dopo il paint.
    const ric: any = (window as any).requestIdleCallback;
    const idleHandle = ric
      ? ric(runGeoDetect, { timeout: 2000 })
      : setTimeout(runGeoDetect, 100);

    return () => {
      clearTimeout(timer);
      ctrl.abort();
      const cic: any = (window as any).cancelIdleCallback;
      if (ric && cic) cic(idleHandle);
      else clearTimeout(idleHandle);
    };
  }, []);

  const setLang = (l: Lang) => {
    setLangState(l);
    if (typeof window !== "undefined") {
      localStorage.setItem(STORAGE_KEY, l);
      localStorage.setItem(STORAGE_LANG_SOURCE, "user");
      document.documentElement.lang = l;
    }
  };

  const setCurrency = (c: Currency) => {
    setCurrencyState(c);
    if (typeof window !== "undefined") {
      localStorage.setItem(STORAGE_CURRENCY, c);
      localStorage.setItem(STORAGE_CURRENCY_SOURCE, "user");
    }
  };

  const CUR_SYMBOLS: Record<string, string> = {
    EUR: "€", GBP: "£", USD: "$", CHF: "CHF",
    DKK: "kr", SEK: "kr", NOK: "kr", ISK: "kr",
    PLN: "zł", CZK: "Kč", HUF: "Ft", BGN: "лв", RON: "lei",
    CAD: "C$", AUD: "A$", NZD: "NZ$",
    JPY: "¥", KRW: "₩", TWD: "NT$", HKD: "HK$", SGD: "S$",
    AED: "AED", QAR: "QAR", KWD: "KWD", SAR: "SAR", ILS: "₪",
  };
  const t = (key: string, vars?: Record<string, string | number>) => {
    let raw = uiTranslations[key] || DICT[key]?.[lang] || DICT[key]?.en || DICT[key]?.it || key;
    if (raw.includes("{cur}")) raw = raw.replaceAll("{cur}", CUR_SYMBOLS[currency] || currency);
    if (vars) {
      for (const k of Object.keys(vars)) raw = raw.replaceAll(`{${k}}`, String(vars[k]));
    }
    return raw;
  };
  const price = (eurAmount: number) => fmtPrice(eurAmount, currency, rates, lang);
  const convert = (eurAmount: number) => {
    const rate = rates[currency] ?? 1;
    return Math.round(eurAmount * rate * 100) / 100;
  };

  return (
    <Ctx.Provider value={{ lang, setLang, t, country, currency, setCurrency, price, convert }}>
      {children}
    </Ctx.Provider>
  );
}

export const useI18n = () => useContext(Ctx);
